package com.nv.commons.dao;import java.sql.Connection;import java.sql.SQLException;import java.sql.Timestamp;import java.util.ArrayList;import java.util.Arrays;import java.util.List;import com.nv.commons.dto.Vendor;import com.nv.commons.model.database.DBQueryRunner;import com.nv.commons.model.database.ResultSetProcessor;import org.apache.commons.lang3.StringUtils;//@Deprecated //not yet usedpublic class VendorDAO {	public static List<Vendor> findAll(Connection conn) throws SQLException {		String sql = "SELECT * FROM vendor";		return DBQueryRunner.getBeanList(conn, Vendor.class, sql);	}	public static Vendor findVendorById(Connection conn, int id) throws SQLException {		String sql = "SELECT code, name FROM vendor WHERE id = ? ";		return DBQueryRunner.getBean(conn, Vendor.class, sql, id);	}//	public static List<Integer> findVendorIdByCode(Connection conn, String... codes) throws SQLException {//		String sql = " SELECT id FROM vendor WHERE code IN (" + StringUtils.repeat("?", ",", codes.length) + ")";////		List<Integer> vendorIdList = new ArrayList<>();////		ResultSetProcessor processor = (index, rs) -> vendorIdList.add(rs.getInt("id"));////		List<Object> params = new ArrayList<>(Arrays.asList(codes));////		DBQueryRunner.processResultSet(conn, processor, sql, params);////		return vendorIdList;//	}	public static List<Vendor> getVendorByUpdateTime(Connection conn, Timestamp updateTime) throws SQLException {		return DBQueryRunner.getBeanList(conn, Vendor.class,			"SELECT * FROM vendor WHERE update_time > ? ORDER BY UPDATE_TIME", updateTime);	}}